// 각 서비스 결과를 순서대로 읽음
const items = $input.all();

const results = items.map(item => item.json);

const now = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });

// 상태 이모지 매핑
const statusEmoji = { ok: '✅', warning: '⚠️', error: '🔴' };
const statusLabel = { ok: '정상', warning: '경고', error: '오류' };

// 전체 상태 결정 (가장 나쁜 상태)
const overallStatus = results.some(r => r.status === 'error')   ? 'error'
                    : results.some(r => r.status === 'warning') ? 'warning'
                    : 'ok';

// 서비스별 섹션 빌드
const sections = results.map(r => {
  const emoji = statusEmoji[r.status];
  const label = statusLabel[r.status];
  const m = r.metrics;

  let detail = '';
  if (r.service === 'Spark Operator') {
    detail = [
      `  • 오퍼레이터: ${m.operatorUp}/${m.operatorTotal} 가동`,
      `  • 전체 잡: ${m.totalApps}개 (실행중 ${m.runningApps} / 성공 ${m.successApps} / 실패 ${m.failedApps})`,
      `  • 최근 1h 신규 실패: ${m.newFailures}건`,
      `  • 실행중 Executor: ${m.executorRun}개`,
    ].join('\n');
  } else if (r.service === 'Strimzi Kafka Operator') {
    detail = [
      `  • 오퍼레이터: ${m.operatorUp}/${m.operatorTotal} 가동`,
      `  • Kafka 클러스터: ${m.healthyClusters}/${m.totalClusters} 정상`,
      `  • 재조정 (성공/실패): ${m.reconSuccess}/${m.reconFailed}`,
      `  • 최근 1h 재조정 실패: ${m.newReconFail}건`,
      `  • 인증서 만료: ${m.certMinDays}일 남음`,
    ].join('\n');
  } else if (r.service === 'CloudNativePG Operator') {
    detail = [
      `  • 오퍼레이터: ${m.operatorUp}/${m.operatorTotal} 가동`,
      `  • Reconcile (성공/오류): ${m.reconSuccessTotal}/${m.reconErrorTotal}`,
      `  • 최근 1h 신규 오류: ${m.newReconErrors}건`,
      `  • Cluster 컨트롤러 오류: ${m.clusterReconError}건`,
      `  • 최근 1h 타임아웃: ${m.reconTimeouts}건`,
    ].join('\n');
  }

  const alertLines = r.alerts.length > 0
    ? '\n  🔔 알림:\n' + r.alerts.map(a => `    - ${a}`).join('\n')
    : '';

  return `${emoji} *${r.service}* — ${label}\n${detail}${alertLines}`;
});

const headerEmoji = statusEmoji[overallStatus];
const headerLabel = statusLabel[overallStatus];

const message = [
  `${headerEmoji} *[Operator Health Check]* 전체 상태: *${headerLabel}*`,
  `🕐 점검 시각: ${now}`,
  '─'.repeat(40),
  sections.join('\n\n'),
  '─'.repeat(40),
  '_이 메시지는 n8n이 매 시간 Prometheus 메트릭을 수집하여 자동 발송합니다._'
].join('\n');

return [{ json: { message, overallStatus } }];
